def utc_timestamp() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")


def main() -> int:
    repo_root = Path.cwd()
    backup_root = repo_root / "tools" / f"_patch_backup_{PATCH_ID}_{utc_timestamp()}"
    backed_up: list[str] = []
    written: list[str] = []
    modified: list[str] = []
    for rel, content in FILES.items():
        target = repo_root / rel
        target.parent.mkdir(parents=True, exist_ok=True)
        if target.exists():
            backup = backup_root / rel
            backup.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(target, backup)
            backed_up.append(rel)
            modified.append(rel)
        target.write_text(content, encoding="utf-8", newline="\n")
        written.append(rel)

    compile_errors: dict[str, str] = {}
    for rel in [
        "src/tradebot/signature_approval_package.py",
        "tools/check_4B436634G_signature_approval_package.py",
        "tools/run_4B436634G_signature_approval_package.py",
        "tests/test_signature_approval_package_4B436634G.py",
    ]:
        try:
            py_compile.compile(str(repo_root / rel), doraise=True)
        except py_compile.PyCompileError as exc:
            compile_errors[rel] = str(exc)

    result = {
        "applied": True,
        "patch_id": PATCH_ID,
        "patch_version": PATCH_VERSION,
        "patch_name": PATCH_NAME,
        "written_files": written,
        "modified_files": modified,
        "backed_up_files": backed_up,
        "backup_root": str(backup_root.relative_to(repo_root)) if backed_up else "",
        "py_compile_ok": not compile_errors,
        "compile_errors": compile_errors,
        "approved_for_live_real": False,
        "approved_for_paper_transition": False,
        "approved_for_exchange_submit": False,
        "approved_for_runtime_overlay": False,
        "archive_execution_allowed": False,
        "archive_move_performed": False,
        "file_delete_performed": False,
        "file_move_performed": False,
        "report_delete_performed": False,
        "destructive_cleanup_performed": False,
        "deduplication_action_performed": False,
        "approval_performed": False,
        "simulated_approval_performed": False,
        "next_phase_unlock_performed": False,
        "transition_to_next_phase_performed": False,
        "exchange_submit_performed": False,
        "order_submit_performed": False,
        "trading_action_performed": False,
        "training_performed": False,
        "reload_performed": False,
        "runtime_overlay_activated": False,
    }
    print(json.dumps(result, indent=2, sort_keys=True))
    return 0 if not compile_errors else 1


if __name__ == "__main__":
    raise SystemExit(main())
